// Validate and normalize incoming clinic data
const items = $input.all();

return items.map(item => {
  const d = item.json;

  // Ensure all expected fields exist with sensible defaults
  return {
    json: {
      nom:                    d.nom                    ?? '',
      adresse:                d.adresse                ?? '',
      ville:                  d.ville                  ?? '',
      telephone:              d.telephone              ?? '',
      email:                  d.email                  ?? '',
      site_web:               d.site_web               ?? '',
      google_maps_rating:     d.google_maps_rating     ?? null,
      google_maps_reviews:    d.google_maps_reviews    ?? null,
      instagram_url:          d.instagram_url          ?? '',
      facebook_url:           d.facebook_url           ?? '',
      instagram_followers:    d.instagram_followers    ?? null,
      facebook_followers:     d.facebook_followers     ?? null,
      derniere_publication:   d.derniere_publication   ?? '',
      services:               Array.isArray(d.services) ? d.services : [],
      publicite_meta_active:  d.publicite_meta_active  ?? null,
      booking_en_ligne:       d.booking_en_ligne       ?? null,
      secteur:                d.secteur                ?? ''
    }
  };
});

// Score each clinic and build the RESEARCHER analysis output
const AESTHETIC_KEYWORDS = new Set([
  'botox','hyaluronique','peeling','laser','lipolyse','rhinoplastie',
  'blépharoplastie','lifting','prp','mésothérapie','épilation',
  'cryolipolyse','hifu','radiofréquence','injections','esthétique',
  'aesthetic','médecine esthétique','chirurgie esthétique','skincare',
  'soin','soins','acide hyaluronique'
]);

const MATURITY_SERVICES = new Set([
  'botox','hyaluronique','laser','lipolyse','prp','mésolift',
  'cryolipolyse','hifu'
]);

function scoreClinic(d) {
  let score = 0;
  const combined = [
    d.secteur,
    ...d.services,
    d.nom
  ].join(' ').toLowerCase();

  if ([...AESTHETIC_KEYWORDS].some(kw => combined.includes(kw))) score += 3;
  if (d.site_web)                                                  score += 1;
  if (d.instagram_url || d.facebook_url)                          score += 1;
  if (d.google_maps_rating >= 4.0)                                score += 1;
  if (d.google_maps_reviews >= 20)                                score += 1;
  if (d.publicite_meta_active === true)                           score += 2;
  else if (d.publicite_meta_active === false)                     score += 1;
  if (d.booking_en_ligne)                                         score += 1;
  return score;
}

function businessSignals(d) {
  const s = [];
  if (d.adresse)             s.push(`Adresse physique renseignée : ${d.adresse}`);
  if (d.google_maps_rating != null) {
    if (d.google_maps_rating >= 4.0)
      s.push(`Bonne réputation Google Maps : ${d.google_maps_rating}/5${d.google_maps_reviews ? ` (${d.google_maps_reviews} avis)` : ''}`);
    else if (d.google_maps_rating >= 3.0)
      s.push(`Réputation Google Maps moyenne : ${d.google_maps_rating}/5`);
    else
      s.push(`Réputation Google Maps faible : ${d.google_maps_rating}/5`);
  }
  if (d.google_maps_reviews >= 50)
    s.push(`Volume d'avis significatif : ${d.google_maps_reviews} avis Google`);
  const premium = d.services.filter(sv => MATURITY_SERVICES.has(sv.toLowerCase()));
  if (premium.length) s.push(`Services premium identifiés : ${premium.join(', ')}`);
  if (d.services.length >= 5) s.push(`Offre de soins diversifiée (${d.services.length} services listés)`);
  if (d.email)            s.push('Email de contact disponible');
  if (d.telephone)        s.push('Numéro de téléphone disponible');
  if (d.booking_en_ligne) s.push('Système de réservation en ligne présent');
  if (d.publicite_meta_active) s.push('Publicité Meta (Facebook/Instagram) déjà active — budget publicitaire confirmé');
  return s;
}

function digitalSignals(d) {
  const s = [];
  if (d.site_web)  s.push(`Site web présent : ${d.site_web}`);
  else             s.push("Pas de site web détecté — opportunité d'acquisition digitale");
  if (d.instagram_url) {
    let line = `Compte Instagram présent : ${d.instagram_url}`;
    if (d.instagram_followers != null) line += ` (${d.instagram_followers} abonnés)`;
    s.push(line);
  }
  if (d.facebook_url) {
    let line = `Page Facebook présente : ${d.facebook_url}`;
    if (d.facebook_followers != null) line += ` (${d.facebook_followers} abonnés)`;
    s.push(line);
  }
  if (d.derniere_publication) s.push(`Dernière publication détectée : ${d.derniere_publication}`);
  if (d.instagram_followers != null && d.instagram_followers < 500)
    s.push("Faible audience Instagram — fort potentiel de croissance organique et payante");
  if (d.publicite_meta_active === false) s.push("Aucune publicité Meta active détectée — opportunité d'acquisition directe");
  if (!d.booking_en_ligne)               s.push("Pas de réservation en ligne — besoin potentiel d'automatisation");
  return s;
}

function missingInfo(d) {
  const m = [];
  if (!d.email)                                 m.push('Email de contact');
  if (!d.telephone)                             m.push('Numéro de téléphone');
  if (!d.site_web)                              m.push('Site web');
  if (!d.instagram_url && !d.facebook_url)      m.push('Présence sur les réseaux sociaux');
  if (d.google_maps_rating == null)             m.push('Note Google Maps');
  if (d.google_maps_reviews == null)            m.push("Nombre d'avis Google");
  if (!d.services.length)                       m.push('Liste des services proposés');
  if (d.publicite_meta_active == null)          m.push('Statut des publicités Meta');
  if (d.booking_en_ligne == null)               m.push("Présence d'un système de réservation en ligne");
  if (!d.derniere_publication)                  m.push('Date de dernière activité sur les réseaux sociaux');
  return m;
}

function buildResume(d) {
  const location = d.ville || (d.adresse ? d.adresse.split(',').pop().trim() : '');
  const locStr   = location ? ` (${location})` : '';
  const sector   = d.secteur || 'clinique';
  let parts = [`${d.nom}${locStr} — ${sector}.`];
  if (d.services.length) parts.push(`Services identifiés : ${d.services.slice(0,5).join(', ')}${d.services.length > 5 ? '…' : '.'}`  );
  if (d.google_maps_rating != null) {
    parts.push(`Note Google : ${d.google_maps_rating}/5${d.google_maps_reviews ? ` sur ${d.google_maps_reviews} avis.` : '.'}`);
  }
  const dp = [];
  if (d.site_web) dp.push('site web');
  if (d.instagram_url) dp.push('Instagram');
  if (d.facebook_url) dp.push('Facebook');
  parts.push(dp.length ? `Présence digitale : ${dp.join(', ')}.` : 'Présence digitale non confirmée.');
  return parts.join(' ');
}

const ORDER = { fort: 0, moyen: 1, faible: 2 };

const results = $input.all().map(item => {
  const d = item.json;
  const score = scoreClinic(d);
  const niveau = score >= 7 ? 'fort' : score >= 4 ? 'moyen' : 'faible';
  return {
    json: {
      nom:               d.nom,
      resume:            buildResume(d),
      signaux_business:  businessSignals(d),
      signaux_digitaux:  digitalSignals(d),
      niveau_pertinence: niveau,
      infos_manquantes:  missingInfo(d)
    }
  };
});

results.sort((a, b) => ORDER[a.json.niveau_pertinence] - ORDER[b.json.niveau_pertinence]);

return results;
